<?php
declare(strict_types=1);namespace App\Repositories\ControlEscaneres;use App\Repositories\ControlEscaneres\Contracts\TransactionManagerInterface;
final class TransactionManager implements TransactionManagerInterface{public function __construct(private \PDO$pdo){}public function begin():void{if(!$this->pdo->inTransaction())$this->pdo->beginTransaction();}public function commit():void{if($this->pdo->inTransaction())$this->pdo->commit();}public function rollback():void{if($this->pdo->inTransaction())$this->pdo->rollBack();}public function transactional(callable$operation):mixed{$this->begin();try{$result=$operation();$this->commit();return$result;}catch(\Throwable$e){$this->rollback();throw$e;}}}
